(self.webpackChunkvuepress_blog=self.webpackChunkvuepress_blog||[]).push([[1609],{8183:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>t});const t={key:"v-1424b29d",path:"/pages/css/dev-experience/",title:"",lang:"zh-CN",frontmatter:{home:!1,sidebar:!1},excerpt:"",headers:[{level:3,title:"font-display",slug:"font-display",children:[]},{level:3,title:"常见的 css link",slug:"常见的-css-link",children:[]},{level:3,title:"purgecss",slug:"purgecss",children:[]},{level:3,title:"sass @use",slug:"sass-use",children:[]}],filePathRelative:"pages/css/dev-experience/README.md",git:{updatedTime:172766637e4,contributors:[{name:"COOKIES-LGL",email:"1344714332@qq.com",commits:6}]}}},8438:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>i});var t=a(6252);const p=(0,t.uE)('<h3 id="font-display"><a class="header-anchor" href="#font-display">#</a> font-display</h3><h4 id="font-face-后文本的渲染过程"><a class="header-anchor" href="#font-face-后文本的渲染过程">#</a> @font-face 后文本的渲染过程</h4><ul><li>下载 web font</li><li>在下载期间先用备选字体渲染</li><li>web font 字体下载完成后使用该字体替换 实际这只是 @font-face 渲染方式的一种，而且不是默认的，@font-face 由 font-display 属性决定 web font 在下载时间和可用时间是如何展示的 在字体下载比较慢的情况下</li><li>如果认为字体切换带来的闪烁不是问题，可以设置 font-display:swap;提前渲染文本</li><li>如果认为不一定要保障使用 web font 来渲染，那么无疑 font-display:optional;是最优选</li></ul><h4 id="提前加载-web-font"><a class="header-anchor" href="#提前加载-web-font">#</a> 提前加载 web font</h4><p>令人意外的是浏览器解析到 @font-face 声明时候并不会下载对应的字体，只有解析到使用了该 font-face 中定义字体的页面元素时，才会下载对应的字体这也就意味着把 @font-face 声明写在页面顶部是没有作用的，可以使用 preconnect 或者 preload 提前让浏览器提前建连和下载字体文件，尤其是在页面应用了流式渲染时候有奇效</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>link</span> <span class="token attr-name">rel</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>preconnect<span class="token punctuation">&quot;</span></span> <span class="token attr-name">href</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>https://fonts.gstatic.com<span class="token punctuation">&quot;</span></span> <span class="token attr-name">crossorigin</span> <span class="token punctuation">/&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>link</span>\n  <span class="token attr-name">rel</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>preload<span class="token punctuation">&quot;</span></span>\n  <span class="token attr-name">href</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>https://fonts.gstatic.com/s/roboto/v30/KFOkCnqEu92Fr1MmgVxFIzIXKMnyrYk.woff2<span class="token punctuation">&quot;</span></span>\n  <span class="token attr-name">as</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>font<span class="token punctuation">&quot;</span></span>\n  <span class="token attr-name">type</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>font/woff2<span class="token punctuation">&quot;</span></span>\n  <span class="token attr-name">crossorigin</span>\n<span class="token punctuation">/&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h4 id="unicode-range-子集化缩减-web-font-体积"><a class="header-anchor" href="#unicode-range-子集化缩减-web-font-体积">#</a> unicode-range 子集化缩减 web font 体积</h4><p>在 @font-face 内部可以使用 unicode-range 定义字体应用到的 Unicode 字符范围。这样可以将字体文件拆分成多个，当字符在定义的范围内时，浏览器才会下载并使用对应的字体文件</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token atrule"><span class="token rule">@font-face</span></span> <span class="token punctuation">{</span>\n  <span class="token property">font-family</span><span class="token punctuation">:</span> <span class="token string">&quot;MyFont&quot;</span><span class="token punctuation">;</span>\n  <span class="token property">src</span><span class="token punctuation">:</span> <span class="token url"><span class="token function">url</span><span class="token punctuation">(</span><span class="token string url">&quot;myfont.woff2&quot;</span><span class="token punctuation">)</span></span> <span class="token function">format</span><span class="token punctuation">(</span><span class="token string">&quot;woff2&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n  <span class="token property">unicode-range</span><span class="token punctuation">:</span> U+00-FF<span class="token punctuation">;</span> <span class="token comment">/* 基本拉丁字母及扩展 */</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h4 id="position-sticky-无效的原因"><a class="header-anchor" href="#position-sticky-无效的原因">#</a> position：sticky 无效的原因</h4><ul><li><p>缺少 top、left、right 或 bottom 属性：为了使 position: sticky 生效，你需要指定至少一个定位属性（如 top、left、right 或 bottom），以定义元素在何时开始粘性定位。</p></li><li><p>父元素没有足够的内容或高度：如果父元素没有足够的内容或高度，导致没有滚动条，sticky 定位可能不会生效，因为没有滚动行为来触发粘性定位。</p></li><li><p>父元素设置了 overflow 属性：如果元素的直接父元素或任何祖先元素设置了 overflow: hidden 或 overflow: auto、scroll，这可能会创建一个新的格式化上下文（formatting context），导致 sticky 定位失效。</p></li><li><p>元素的祖先元素使用了 transform 属性：如果元素的任何祖先元素使用了 transform 属性，这可能会创建一个新的包含块（containing block），这会影响 sticky 定位的行为。</p></li><li><p>position: sticky 仅在元素的父容器是块级元素（block-level element）时有效。如果父容器是内联元素（inline element），粘性定位将不起作用</p></li></ul><h3 id="常见的-css-link"><a class="header-anchor" href="#常见的-css-link">#</a> 常见的 css link</h3><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>link</span> <span class="token attr-name">href</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>example.css<span class="token punctuation">&quot;</span></span> <span class="token attr-name">rel</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>stylesheet<span class="token punctuation">&quot;</span></span> <span class="token attr-name">type</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>text/css<span class="token punctuation">&quot;</span></span> <span class="token attr-name">media</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>all<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>media 属性规定被链接文档将显示在什么设备上，利用这个属性就衍生出了很多优化方式。</p><p>1、比如将不同屏幕尺寸所需的 css 分开加载，可以缩小加载 css 文件的体积。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>link</span>\n  <span class="token attr-name">href</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>example-pc.css<span class="token punctuation">&quot;</span></span>\n  <span class="token attr-name">rel</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>stylesheet<span class="token punctuation">&quot;</span></span>\n  <span class="token attr-name">type</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>text/css<span class="token punctuation">&quot;</span></span>\n  <span class="token attr-name">media</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>screen and (min-width: 768px)<span class="token punctuation">&quot;</span></span>\n<span class="token punctuation">/&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>link</span> <span class="token attr-name">href</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>example-m.css<span class="token punctuation">&quot;</span></span> <span class="token attr-name">rel</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>stylesheet<span class="token punctuation">&quot;</span></span> <span class="token attr-name">type</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>text/css<span class="token punctuation">&quot;</span></span> <span class="token attr-name">media</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>screen and (max-width: 767px)<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>2、 尽可能的拆分主体样式文件，并将非关键的 css link 的 media 属性设置为 none 当 media 属性为 none 时，浏览器会以最低优先级加载此文件，并不会阻塞页面的渲染进程</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>link</span> <span class="token attr-name">rel</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>stylesheet<span class="token punctuation">&quot;</span></span> <span class="token attr-name">href</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>footer.css<span class="token punctuation">&quot;</span></span> <span class="token attr-name">media</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>none<span class="token punctuation">&quot;</span></span> <span class="token attr-name">onload</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>this.media=<span class="token punctuation">&#39;</span>all<span class="token punctuation">&#39;</span><span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>3、对于主体样式的预加载</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>link</span> <span class="token attr-name">rel</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>preload<span class="token punctuation">&quot;</span></span> <span class="token attr-name">href</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>common.css<span class="token punctuation">&quot;</span></span> <span class="token attr-name">as</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>style<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="purgecss"><a class="header-anchor" href="#purgecss">#</a> purgecss</h3>',21),e=(0,t.Uk)("一个用来删除未使用的 CSS 代码的工具 "),o={href:"https://www.purgecss.cn/",target:"_blank",rel:"noopener noreferrer"},l=(0,t.Uk)("purgecss"),c=(0,t.Wm)("h3",{id:"sass-use"},[(0,t.Wm)("a",{class:"header-anchor",href:"#sass-use"},"#"),(0,t.Uk)(" sass @use")],-1),u=(0,t.Wm)("p",null,"@use 规则与 @import 规则不同。@import 规则是 Sass 较早提供的引入机制，它不支持命名空间，并且会将引入的文件内容全部复制到当前文件中。 而 @use 规则则提供了更好的封装和模块化支持，它允许你通过命名空间来访问引入的文件中的内容，从而避免了命名冲突和不必要的代码复制",-1),i={render:function(n,s){const a=(0,t.up)("OutboundLink");return(0,t.wg)(),(0,t.j4)(t.HY,null,[p,(0,t.Wm)("p",null,[e,(0,t.Wm)("a",o,[l,(0,t.Wm)(a)])]),c,u],64)}}}}]);